# Bu betik index.html'i dogru (guncel, tum yeni ozellikleri iceren) icerikle
# YENIDEN YAZAR. Base64 kullanildigi icin encoding sorunlarindan etkilenmez.
$b64 = ""
$bytes = [Convert]::FromBase64String($b64)
[System.IO.File]::WriteAllBytes("index.html", $bytes)
Write-Host "index.html basariyla yeniden yazildi. Boyut:" (Get-Item index.html).Length "bayt (beklenen: 29510)"
